import React from 'react'
import styled from 'styled-components'


const FooterWrapper = styled.div `
display:flex;
flex-direction:column;
background-color:#373C38;
justify-content:center;
align-items:center;
width:100vw;
height:20vh;
padding:20px 0px;
`

const Head = styled.div `
color:white;
margin:30px 0px;
`

const Content = styled.div `
display:flex;
justify-content:space-between;
width:35vw;
`

const Item = styled.div `
font-size:0.9rem;
color:white;
`



export default function Footer () {
	return (
		<FooterWrapper>
			<Head>Created by Noah Hong</Head>
			<Content>
				<Item>LinkedIn</Item>
				<Item>Instagram</Item>
				<Item>Twitter</Item>
				<Item>Github</Item>
			</Content>
		</FooterWrapper>
	)
}
